    UR: { kanton: 'UR', erlassName: "Grundbuchgebührentarif (Tarifordnung der Justizdirektion Uri vom 4. Dezember 2024)", erlassNr: "gestützt auf RB 3.2521 (Gebührenreglement) Art. 8a und RB 9.3408 (Reglement über das Grundbuch) Art. 2 Abs. 2; der Tarif selbst ist eine Tarifordnung der Justizdirektion ohne eigene RB-Nummer", artikel: "Grundbuchgebuehrentarif UR Art. 12 lit. b (RB 9.3408)", stand: "1.1.2025", verifiziert: R, quelleUrl: "https://www.ur.ch/online-schalter/2127/download", hinweis: "KORREKTUR: Begruendung von Stockwerkeigentum = CHF 100 pro Stockwerkeinheit (Art. 12 lit. b). Aenderung von Wertquoten = CHF 100 pro Einheit (lit. c). Alle Positionen Art. 12 lit. a-f betragen einheitlich CHF 100. Bisheriger Wert 100 korrekt; ist pro Einheit zu verstehen.", regel: { typ: 'fix', chf: 100 } },
    VD: { kanton: 'VD', erlassName: "Loi du 9 octobre 2012 sur le registre foncier (LRF), Chapitre V Emoluments (art. 26-29), en lien avec le Règlement du 2 juillet 2014 fixant le tarif des émoluments du registre foncier (RE-RF)", erlassNr: "BLV 211.61 (LRF) / BLV 211.61.1 (RE-RF)", artikel: "Art. 2 al.1 lit.b RE-RF (BLV 211.61.1)", stand: "01.07.2014", verifiziert: R, quelleUrl: "https://www.lexfind.ch/tolv/210360/fr", hinweis: "Art. 2 al.1 lit.b RE-RF: Eintragung/Aenderung des Begruendungsakts von Stockwerkeigentum (propriété par étages) bzw. Miteigentum mit Nutzungsreglement = forfait de base CHF 200 PLUS CHF 50 pro eroeffnetem/geaendertem Blatt (lot/quote-part). fixChf=200 als Grundpauschale; je Stock", regel: { typ: 'fix', chf: 200 } },
    VS: { kanton: 'VS', erlassName: "Ordonnance cantonale sur le registre foncier (OcRF) / Kantonale Grundbuchverordnung (kGBV)", erlassNr: "211.611", artikel: "Art. 33 al. 2 let. a ch. 2 OcRF (PPE 100 CHF) i.V.m. let. c ch. 1 (immatriculation part PPE 20 CHF/Einheit), RS 211.611", stand: "01.10.2025", verifiziert: R, quelleUrl: "https://lex.vs.ch/app/fr/texts_of_law/211.611", hinweis: "Grundbetrag 100 CHF fuer Begruendung/Aenderung/Aufhebung der PPE (let. a ch. 2.1/2.2/2.3). ZUSAETZLICH 20 CHF PRO Stockwerkeinheit fuer immatriculation/modification d'une part de PPE (let. c ch. 1.1/1.2). KORREKTUR: einheitsabhaengiger Zuschlag (20 CHF x Anzahl Einheiten) fehlte", regel: { typ: 'fix', chf: 100 } },
    ZG: { kanton: 'ZG', erlassName: "Gesetz über den Gebührentarif im Grundbuchwesen (Grundbuchgebührentarif)", erlassNr: "BGS 215.35", artikel: "BGS 215.35 § 13 Abs. 2 i.V.m. § 14 Abs. 1 lit. c", stand: "2026-06-16", verifiziert: R, quelleUrl: "https://bgs.zg.ch/app/de/texts_of_law/215.35", hinweis: "KORREKTUR: kein Vereinbarungstarif. Stundenansatz Fr. 180.- je angebrochene Viertelstunde (§ 13 Abs. 2), Faktor 4 bei Stockwerkeigentumsbegruendungen bis zur Gebuehren-Grenze Fr. 13'500.- (§ 14 Abs. 1 lit. c). Ueber Grenze kein Faktor (§ 14 Abs. 3).", regel: { typ: 'formel_extern', hinweis: "Nach Zeitaufwand, Stundenansatz CHF 180. KORREKTUR: kein Vereinbarungstarif. Stundenansatz Fr. 180.- je angebrochene Viertelstunde (§ 13 Abs. 2), Faktor 4 bei Stockwerkeigentumsbegruendungen bis zur Gebuehren-Grenze Fr." } },
    ZH: { kanton: 'ZH', erlassName: "Notariatsgebührenverordnung (NotGebV)", erlassNr: "LS 243", artikel: "NotGebV LS 243, Anhang Ziff. 2.1 (Aufnahme eines Grundstuecks - Stockwerkeigentumsanteil)", stand: "01.01.2024", verifiziert: R, quelleUrl: "https://www.zh.ch/de/politik-staat/gesetze-beschluesse/gesetzessammlung/zhlex-ls/erlass-243-2009_03_09-2009_07_01-123.html", hinweis: "Aufnahme jedes StWE-Anteils als Grundstueck: Ziff. 2.1, pro Grundstueck 50-500. Die BEURKUNDUNG der Begruendung von Stockwerkeigentum ist separat Ziff. 1.3 (pro Einheit 50-100, pro aufgeteiltes Grundstueck mind. 1000). Beschriebsaenderung StWE: Ziff. 2.6.2 (50-200). MwSt nach § 2", regel: { typ: 'rahmen', vonChf: 50, bisChf: 500 } },
